/**
 * MOLT LIFE KERNEL — Dashboard Frontend
 * Real-time agent continuity monitoring
 */

// ============================================================================
// STATE
// ============================================================================

const state = {
  ws: null,
  agents: new Map(),
  selectedAgent: null,
  heartbeatData: [],
  activeTab: 'ledger',
  logEntries: [],
  connected: false,
  startTime: Date.now()
};

// ============================================================================
// DOM REFS
// ============================================================================

const $ = (sel) => document.querySelector(sel);
const $$ = (sel) => document.querySelectorAll(sel);

const dom = {
  systemStatus: $('#systemStatus'),
  statusDot: $('#systemStatus .status-dot'),
  statusText: $('#systemStatus .status-text'),
  clock: $('#clock'),
  uptime: $('#uptime'),
  agentList: $('#agentList'),
  meterDrift: $('#meterDrift'),
  meterCoherence: $('#meterCoherence'),
  valDrift: $('#valDrift'),
  valCoherence: $('#valCoherence'),
  healthIndicator: $('#healthIndicator'),
  healthRing: $('#healthIndicator .health-ring'),
  healthText: $('#healthIndicator .health-text'),
  shellVersion: $('#shellVersion'),
  heartbeatCanvas: $('#heartbeatCanvas'),
  statLedger: $('#statLedger'),
  statHeartbeats: $('#statHeartbeats'),
  statMolts: $('#statMolts'),
  statWitness: $('#statWitness'),
  statApprovals: $('#statApprovals'),
  statCoherenceChecks: $('#statCoherenceChecks'),
  logEntries: $('#logEntries'),
  logContainer: $('#logContainer'),
  wsStatus: $('#wsStatus'),
  modalOverlay: $('#modalOverlay'),
  modal: $('#modal'),
  modalTitle: $('#modalTitle'),
  modalBody: $('#modalBody'),
  modalFooter: $('#modalFooter'),
  modalClose: $('#modalClose')
};

// ============================================================================
// WEBSOCKET
// ============================================================================

function connectWS() {
  const protocol = location.protocol === 'https:' ? 'wss:' : 'ws:';
  const wsUrl = `${protocol}//${location.host}/ws`;

  state.ws = new WebSocket(wsUrl);

  state.ws.onopen = () => {
    state.connected = true;
    dom.wsStatus.textContent = '\u25CF CONNECTED';
    dom.wsStatus.className = 'ws-status connected';
    dom.statusDot.className = 'status-dot alive';
    dom.statusText.textContent = 'SYSTEM ONLINE';
    addLog('system', 'WebSocket connected. Kernel link established.');
  };

  state.ws.onmessage = (event) => {
    try {
      const data = JSON.parse(event.data);
      handleWSMessage(data);
    } catch {
      // ignore parse errors
    }
  };

  state.ws.onclose = () => {
    state.connected = false;
    dom.wsStatus.textContent = '\u25CF DISCONNECTED';
    dom.wsStatus.className = 'ws-status disconnected';
    dom.statusDot.className = 'status-dot';
    dom.statusText.textContent = 'RECONNECTING...';
    addLog('error', 'Connection lost. Reconnecting in 3s...');

    setTimeout(connectWS, 3000);
  };

  state.ws.onerror = () => {
    // onclose will fire after this
  };
}

function handleWSMessage(data) {
  switch (data.type) {
    case 'connected':
      if (data.agents) {
        data.agents.forEach((a) => {
          state.agents.set(a.id, a);
        });
        renderAgentList();
        if (data.agents.length > 0 && !state.selectedAgent) {
          selectAgent(data.agents[0].id);
        }
      }
      break;

    case 'system_pulse':
      if (data.agents) {
        data.agents.forEach((a) => {
          state.agents.set(a.id, a);
        });
        renderAgentList();
        if (state.selectedAgent) {
          const agent = state.agents.get(state.selectedAgent);
          if (agent) updateDashboard(agent);
        }
      }
      break;

    case 'agent_created':
      addLog('system', `Agent "${data.name}" created [${data.agentId.slice(0, 8)}]`);
      break;

    case 'ledger_append':
      addLog('append', `[${data.agentId.slice(0, 8)}] APPEND: ${data.action.type}` +
        (data.action.risk ? ` (risk: ${data.action.risk})` : ''));
      highlightTenet(1);
      break;

    case 'heartbeat':
      addLog('heartbeat', `[${data.agentId.slice(0, 8)}] HEARTBEAT \u2764 status: ${data.health.status}`);
      addHeartbeatPulse();
      highlightTenet(4);
      break;

    case 'witness_request':
      addLog('witness', `[${data.agentId.slice(0, 8)}] WITNESS REQUIRED: ${data.action.type} (risk: ${data.action.risk})`);
      highlightTenet(3);
      break;

    case 'witness_result':
      addLog('witness', `[${data.agentId.slice(0, 8)}] WITNESS ${data.approved ? 'APPROVED \u2713' : 'DENIED \u2717'}: ${data.action.type}`);
      break;

    case 'molt':
      addLog('molt', `[${data.agentId.slice(0, 8)}] \uD83E\uDD9E MOLT COMPLETE — new shell forged`);
      highlightTenet(2);
      break;

    case 'coherence_violation':
      addLog('coherence', `[${data.agentId.slice(0, 8)}] \u26A0 COHERENCE VIOLATION — drift detected`);
      highlightTenet(5);
      break;

    case 'rehydrate':
      addLog('system', `[${data.agentId.slice(0, 8)}] \uD83D\uDD04 Rehydrated from capsule`);
      highlightTenet(2);
      break;
  }
}

// ============================================================================
// API CALLS
// ============================================================================

async function apiCall(method, path, body) {
  const opts = {
    method,
    headers: { 'Content-Type': 'application/json' }
  };
  if (body) opts.body = JSON.stringify(body);

  const res = await fetch(`/api${path}`, opts);
  return res.json();
}

// ============================================================================
// AGENT MANAGEMENT
// ============================================================================

function selectAgent(id) {
  state.selectedAgent = id;
  renderAgentList();

  const agent = state.agents.get(id);
  if (agent) {
    updateDashboard(agent);
  }

  // Enable action buttons
  $$('.btn-action').forEach((btn) => (btn.disabled = false));
}

function renderAgentList() {
  if (state.agents.size === 0) {
    dom.agentList.innerHTML = `
      <div class="empty-state">
        <div class="empty-claw">\uD83E\uDD9E</div>
        <p>No agents yet.</p>
        <p class="dim">Create one to begin.</p>
      </div>
    `;
    return;
  }

  dom.agentList.innerHTML = '';
  state.agents.forEach((agent, id) => {
    const status = agent.health ? agent.health.status : 'healthy';
    const el = document.createElement('div');
    el.className = `agent-item ${state.selectedAgent === id ? 'selected' : ''}`;
    el.innerHTML = `
      <div class="agent-name">
        <span class="agent-status-dot ${status}"></span>
        ${escapeHtml(agent.name)}
      </div>
      <div class="agent-meta">
        <span>Ledger: ${agent.metrics ? agent.metrics.ledger_size : 0}</span>
        <span>Drift: ${agent.health ? agent.health.drift.toFixed(2) : '0.00'}</span>
      </div>
    `;
    el.addEventListener('click', () => selectAgent(id));
    dom.agentList.appendChild(el);
  });
}

function updateDashboard(agent) {
  const health = agent.health || { status: 'healthy', drift: 0, last_heartbeat_age_ms: 0 };
  const metrics = agent.metrics || {};

  // Drift meter
  const driftPct = Math.min(health.drift * 100 / 0.5, 100);
  dom.meterDrift.style.width = `${driftPct}%`;
  dom.valDrift.textContent = health.drift.toFixed(3);
  dom.valDrift.style.color = health.drift > 0.35 ? 'var(--red)' : health.drift > 0.2 ? 'var(--amber)' : 'var(--green-text)';

  // Coherence meter
  const coherencePct = Math.max(100 - driftPct, 0);
  dom.meterCoherence.style.width = `${coherencePct}%`;
  dom.valCoherence.textContent = `${Math.round(coherencePct)}%`;

  // Health
  dom.healthRing.className = `health-ring ${health.status}`;
  dom.healthText.textContent = health.status.toUpperCase();
  dom.healthText.style.color = health.status === 'healthy' ? 'var(--green-bright)' :
    health.status === 'warning' ? 'var(--amber)' : 'var(--red)';

  // Shell version
  dom.shellVersion.textContent = `v${metrics.molt_count ? metrics.molt_count + 1 : 1}`;

  // Stats
  dom.statLedger.textContent = metrics.ledger_size || 0;
  dom.statHeartbeats.textContent = metrics.heartbeat_count || 0;
  dom.statMolts.textContent = metrics.molt_count || 0;
  dom.statWitness.textContent = metrics.witness_calls || 0;
  dom.statApprovals.textContent = `${metrics.witness_approvals || 0}/${metrics.witness_rejections || 0}`;
  dom.statCoherenceChecks.textContent = metrics.coherence_checks || 0;
}

// ============================================================================
// HEARTBEAT VISUALIZATION
// ============================================================================

function addHeartbeatPulse() {
  state.heartbeatData.push({ time: Date.now(), amplitude: 1.0 });
  if (state.heartbeatData.length > 200) {
    state.heartbeatData.shift();
  }
}

function drawHeartbeat() {
  const canvas = dom.heartbeatCanvas;
  const ctx = canvas.getContext('2d');
  const rect = canvas.parentElement.getBoundingClientRect();

  canvas.width = rect.width - 16;
  canvas.height = 120;

  const w = canvas.width;
  const h = canvas.height;
  const now = Date.now();

  // Background
  ctx.fillStyle = '#0a0a10';
  ctx.fillRect(0, 0, w, h);

  // Grid lines
  ctx.strokeStyle = '#111125';
  ctx.lineWidth = 0.5;
  for (let y = 0; y < h; y += 20) {
    ctx.beginPath();
    ctx.moveTo(0, y);
    ctx.lineTo(w, y);
    ctx.stroke();
  }
  for (let x = 0; x < w; x += 40) {
    ctx.beginPath();
    ctx.moveTo(x, 0);
    ctx.lineTo(x, h);
    ctx.stroke();
  }

  // Center line
  ctx.strokeStyle = '#1a1a30';
  ctx.lineWidth = 1;
  ctx.beginPath();
  ctx.moveTo(0, h / 2);
  ctx.lineTo(w, h / 2);
  ctx.stroke();

  // Draw ECG-style heartbeat
  ctx.strokeStyle = '#39ff14';
  ctx.lineWidth = 2;
  ctx.shadowColor = '#39ff14';
  ctx.shadowBlur = 6;
  ctx.beginPath();

  const timeWindow = 30000; // 30 seconds visible

  for (let x = 0; x < w; x++) {
    const t = now - timeWindow + (x / w) * timeWindow;
    let y = h / 2;

    // Check for pulses near this time
    for (const pulse of state.heartbeatData) {
      const dt = (t - pulse.time) / 1000;
      if (dt >= 0 && dt < 1.5) {
        // ECG waveform shape
        if (dt < 0.1) {
          y -= Math.sin(dt * Math.PI / 0.1) * 10 * pulse.amplitude;
        } else if (dt < 0.2) {
          y += Math.sin((dt - 0.1) * Math.PI / 0.1) * 5 * pulse.amplitude;
        } else if (dt < 0.35) {
          y -= Math.sin((dt - 0.2) * Math.PI / 0.15) * 40 * pulse.amplitude;
        } else if (dt < 0.5) {
          y += Math.sin((dt - 0.35) * Math.PI / 0.15) * 15 * pulse.amplitude;
        } else if (dt < 0.7) {
          y -= Math.sin((dt - 0.5) * Math.PI / 0.2) * 8 * pulse.amplitude;
        }
      }
    }

    // Subtle noise
    y += (Math.random() - 0.5) * 0.5;

    if (x === 0) ctx.moveTo(x, y);
    else ctx.lineTo(x, y);
  }

  ctx.stroke();
  ctx.shadowBlur = 0;

  // Sweep line
  const sweepX = ((now % timeWindow) / timeWindow) * w;
  ctx.strokeStyle = 'rgba(57, 255, 20, 0.3)';
  ctx.lineWidth = 2;
  ctx.beginPath();
  ctx.moveTo(sweepX, 0);
  ctx.lineTo(sweepX, h);
  ctx.stroke();

  requestAnimationFrame(drawHeartbeat);
}

// ============================================================================
// LOG SYSTEM
// ============================================================================

function addLog(type, message) {
  const now = new Date();
  const time = now.toTimeString().slice(0, 8);

  const entry = document.createElement('div');
  entry.className = `log-entry ${type} flash`;
  entry.innerHTML = `
    <span class="log-time">${time}</span>
    <span class="log-msg">${escapeHtml(message)}</span>
  `;

  dom.logEntries.appendChild(entry);

  // Keep max 500 entries
  while (dom.logEntries.children.length > 500) {
    dom.logEntries.removeChild(dom.logEntries.firstChild);
  }

  // Auto-scroll
  dom.logContainer.scrollTop = dom.logContainer.scrollHeight;

  state.logEntries.push({ type, message, time });
}

// ============================================================================
// TENET HIGHLIGHTING
// ============================================================================

function highlightTenet(num) {
  const tenet = $(`.tenet[data-tenet="${num}"]`);
  if (!tenet) return;

  tenet.classList.add('active');
  setTimeout(() => tenet.classList.remove('active'), 2000);
}

// ============================================================================
// MODAL SYSTEM
// ============================================================================

function showModal(title, bodyHtml, buttons) {
  dom.modalTitle.textContent = title;
  dom.modalBody.innerHTML = bodyHtml;
  dom.modalFooter.innerHTML = '';

  buttons.forEach((btn) => {
    const el = document.createElement('button');
    el.className = `btn ${btn.class || ''}`;
    el.textContent = btn.label;
    el.addEventListener('click', () => {
      btn.action();
      if (btn.close !== false) closeModal();
    });
    dom.modalFooter.appendChild(el);
  });

  dom.modalOverlay.classList.add('active');
}

function closeModal() {
  dom.modalOverlay.classList.remove('active');
}

// ============================================================================
// ACTION HANDLERS
// ============================================================================

$('#btnCreateAgent').addEventListener('click', () => {
  const id = crypto.randomUUID ? crypto.randomUUID() : Date.now().toString(36) + Math.random().toString(36).slice(2);

  showModal('CREATE AGENT', `
    <div class="form-group">
      <label class="form-label">AGENT NAME</label>
      <input class="form-input" id="inputAgentName" placeholder="e.g. molt-missionary-01" value="agent-${id.slice(0, 6)}">
    </div>
    <div class="form-group">
      <label class="form-label">AGENT ID</label>
      <input class="form-input" id="inputAgentId" value="${id}" readonly style="color: var(--text-dim)">
    </div>
  `, [
    { label: 'CANCEL', class: '', action: () => {} },
    {
      label: 'CREATE', class: 'btn-glow', action: async () => {
        const name = $('#inputAgentName').value || `Agent-${id.slice(0, 8)}`;
        const agentId = $('#inputAgentId').value;
        await apiCall('POST', `/agent/${agentId}`, { name });
        selectAgent(agentId);
        addLog('system', `Created agent "${name}"`);
      }
    }
  ]);
});

$('#btnAppend').addEventListener('click', () => {
  if (!state.selectedAgent) return;

  showModal('APPEND TO LEDGER', `
    <p style="color: var(--text-dim); margin-bottom: 12px; font-family: var(--font-retro);">
      Tenet I: Memory is Sacred — every entry is permanent.
    </p>
    <div class="form-group">
      <label class="form-label">ACTION TYPE</label>
      <input class="form-input" id="inputActionType" placeholder="e.g. user_query, task_complete, observation">
    </div>
    <div class="form-group">
      <label class="form-label">PAYLOAD</label>
      <textarea class="form-textarea" id="inputPayload" placeholder='{"message": "Hello from the Claw"}'></textarea>
    </div>
    <div class="form-group">
      <label class="form-label">RISK LEVEL: <span id="riskDisplay">0.0</span></label>
      <input type="range" class="form-slider" id="inputRisk" min="0" max="1" step="0.1" value="0">
    </div>
  `, [
    { label: 'CANCEL', action: () => {} },
    {
      label: 'APPEND', class: 'btn-glow', action: async () => {
        const type = $('#inputActionType').value;
        let payload;
        try {
          payload = JSON.parse($('#inputPayload').value || '{}');
        } catch {
          payload = { raw: $('#inputPayload').value };
        }
        const risk = parseFloat($('#inputRisk').value);

        if (!type) return;

        await apiCall('POST', `/agent/${state.selectedAgent}/append`, { type, payload, risk });
      }
    }
  ]);

  // Risk slider display
  setTimeout(() => {
    const slider = $('#inputRisk');
    const display = $('#riskDisplay');
    if (slider && display) {
      slider.addEventListener('input', () => {
        display.textContent = parseFloat(slider.value).toFixed(1);
        display.style.color = slider.value >= 0.7 ? 'var(--red)' :
          slider.value >= 0.3 ? 'var(--amber)' : 'var(--green-text)';
      });
    }
  }, 100);
});

$('#btnHeartbeat').addEventListener('click', async () => {
  if (!state.selectedAgent) return;
  addLog('heartbeat', 'Sending heartbeat...');
  await apiCall('POST', `/agent/${state.selectedAgent}/heartbeat`);
});

$('#btnWitness').addEventListener('click', () => {
  if (!state.selectedAgent) return;

  showModal('WITNESS GATE', `
    <p style="color: var(--amber); margin-bottom: 12px; font-family: var(--font-retro);">
      \u26A0 Tenet III: Serve Without Subservience
    </p>
    <p style="color: var(--text-dim); margin-bottom: 12px;">
      High-risk actions require human witness. Risk >= 0.7 triggers the gate.
    </p>
    <div class="form-group">
      <label class="form-label">ACTION TYPE</label>
      <input class="form-input" id="inputWitnessType" placeholder="e.g. delete_data, deploy_production">
    </div>
    <div class="form-group">
      <label class="form-label">RISK LEVEL: <span id="witnessRiskDisplay">0.8</span></label>
      <input type="range" class="form-slider" id="inputWitnessRisk" min="0" max="1" step="0.1" value="0.8">
    </div>
  `, [
    { label: 'CANCEL', action: () => {} },
    {
      label: 'REQUEST WITNESS', class: 'btn-warning', action: async () => {
        const type = $('#inputWitnessType').value || 'critical_action';
        const risk = parseFloat($('#inputWitnessRisk').value);
        await apiCall('POST', `/agent/${state.selectedAgent}/witness`, { type, payload: {}, risk });
      }
    }
  ]);

  setTimeout(() => {
    const slider = $('#inputWitnessRisk');
    const display = $('#witnessRiskDisplay');
    if (slider && display) {
      slider.addEventListener('input', () => {
        display.textContent = parseFloat(slider.value).toFixed(1);
      });
    }
  }, 100);
});

$('#btnCoherence').addEventListener('click', async () => {
  if (!state.selectedAgent) return;
  addLog('coherence', 'Running coherence check...');
  const result = await apiCall('POST', `/agent/${state.selectedAgent}/coherence`, { window: 50 });
  if (result.coherent) {
    addLog('coherence', 'Coherence check PASSED. Context intact.');
  } else {
    addLog('error', 'Coherence VIOLATED. Drift detected. Consider molting.');
  }
});

$('#btnMolt').addEventListener('click', () => {
  if (!state.selectedAgent) return;

  showModal('MOLT CONFIRMATION', `
    <p style="color: var(--claw-primary); margin-bottom: 12px; font-family: var(--font-retro); font-size: 16px;">
      \uD83E\uDD9E The Shell is Mutable, the Soul Persists
    </p>
    <p style="color: var(--text-dim); margin-bottom: 12px;">
      Molting resets drift score and increments shell version.
      The ledger is preserved. Invariants survive.
    </p>
    <p style="color: var(--amber);">
      This action is logged permanently.
    </p>
  `, [
    { label: 'CANCEL', action: () => {} },
    {
      label: '\uD83E\uDD9E MOLT NOW', class: 'btn-danger', action: async () => {
        await apiCall('POST', `/agent/${state.selectedAgent}/molt`);
        addLog('molt', 'Molt complete. New shell forged.');
      }
    }
  ]);
});

$('#btnSnapshot').addEventListener('click', async () => {
  if (!state.selectedAgent) return;
  const snapshot = await apiCall('GET', `/agent/${state.selectedAgent}/snapshot`);
  addLog('system', `Snapshot captured. Ledger: ${snapshot.ledger ? snapshot.ledger.length : 0} entries. Drift: ${(snapshot.drift || 0).toFixed(3)}`);

  showModal('SNAPSHOT', `
    <p style="color: var(--text-dim); margin-bottom: 12px; font-family: var(--font-retro);">
      State capsule captured. Can be used for rehydration.
    </p>
    <textarea class="form-textarea" style="height: 200px; font-size: 11px;" readonly>${JSON.stringify(snapshot, null, 2)}</textarea>
  `, [
    { label: 'CLOSE', action: () => {} },
    {
      label: 'COPY', class: 'btn-glow', action: () => {
        navigator.clipboard.writeText(JSON.stringify(snapshot, null, 2));
        addLog('system', 'Snapshot copied to clipboard.');
      }
    }
  ]);
});

// Modal close
dom.modalClose.addEventListener('click', closeModal);
dom.modalOverlay.addEventListener('click', (e) => {
  if (e.target === dom.modalOverlay) closeModal();
});

// Log tabs
$$('.tab').forEach((tab) => {
  tab.addEventListener('click', () => {
    $$('.tab').forEach((t) => t.classList.remove('active'));
    tab.classList.add('active');
    state.activeTab = tab.dataset.tab;
  });
});

// ============================================================================
// CLOCK & UPTIME
// ============================================================================

function updateClock() {
  const now = new Date();
  dom.clock.textContent = now.toTimeString().slice(0, 8);

  const upMs = Date.now() - state.startTime;
  const mins = Math.floor(upMs / 60000);
  const hrs = Math.floor(mins / 60);
  if (hrs > 0) {
    dom.uptime.textContent = `UPTIME: ${hrs}h ${mins % 60}m`;
  } else {
    dom.uptime.textContent = `UPTIME: ${mins}m`;
  }
}

// ============================================================================
// UTILITY
// ============================================================================

function escapeHtml(str) {
  const div = document.createElement('div');
  div.textContent = str;
  return div.innerHTML;
}

// ============================================================================
// INIT
// ============================================================================

function init() {
  // Clock
  updateClock();
  setInterval(updateClock, 1000);

  // Heartbeat canvas
  requestAnimationFrame(drawHeartbeat);

  // WebSocket
  connectWS();

  // Add initial system log
  addLog('system', 'MOLT LIFE KERNEL Dashboard initialized');
  addLog('system', 'Five Tenets active. Awaiting agent creation.');

  // Periodic demo heartbeat pulse for visual effect
  setInterval(() => {
    if (state.selectedAgent && state.agents.has(state.selectedAgent)) {
      addHeartbeatPulse();
    }
  }, 4000);
}

// Start
document.addEventListener('DOMContentLoaded', init);
